#include <stdio.h>
int main() {
    int T;
    scanf("%d", &T);
    while (T--) {
        int n, m, c;
        scanf("%d %d %d", &n, &m, &c);
        int count = 0;
        for (int x = 1; x * x <= c; x++) {
            if (c % x == 0) {
                if (x <= n && c / x <= m) count++;
                if (x * x != c && c / x <= n && x <= m) count++;
            }
        }
        printf("%d\n", count);
    }
    return 0;
}

