        while (T-- > 0) {
            int n = sc.nextInt();
            int m = sc.nextInt();
            int c = sc.nextInt();
            int count = 0;
            for (int x = 1; x * x <= c; x++) {
                if (c % x == 0) {
                    if (x <= n && c / x <= m) count++;
                    if (x * x != c && c / x <= n && x <= m) count++;
                }
            }
            System.out.println(count);
        }
    }
}

